function buildActiveSessionCard(
	liveState: LoadedLiveSession,
	checkpoint: LoadedCheckpointRecord | undefined,
	commitsByCheckpointId: Map<string, CheckpointCommit[]>,
	canOpenTranscript: boolean,
): EntireActiveSessionCard {
