function renderDetailState(detail: EntireSessionDetailModel): string {
	const statsParts = [
		`${detail.checkpointCount} checkpoint${detail.checkpointCount === 1 ? "" : "s"}`,
		typeof detail.turnCount === "number" ? `${detail.turnCount} turn${detail.turnCount === 1 ? "" : "s"}` : undefined,
		typeof detail.toolCount === "number" ? `${detail.toolCount} tool${detail.toolCount === 1 ? "" : "s"}` : undefined,
		typeof detail.tokenCount === "number" ? `${formatTokenCount(detail.tokenCount)} tokens` : undefined,
	].filter((part): part is string => typeof part === "string");

	const metaCards = [
		renderMetaCard("Session ID", detail.sessionId),
		renderMetaCard("Source", detail.source === "live" ? "Live session" : "Checkpoint snapshot"),
		renderMetaCard("Started", formatShortTimestamp(detail.startedAt)),
		renderMetaCard("Last Active", formatShortTimestamp(detail.lastActivityAt)),
		renderMetaCard("Duration", formatDuration(detail.durationMs)),
		renderMetaCard("Model", detail.model),
		renderMetaCard("Stats", statsParts.join(" · ")),
		renderMetaCard("Attribution", formatAttribution(detail)),
	].filter((card): card is string => typeof card === "string");

	return `<div class="layout">
	<header class="summary">
		<div class="summary__top">
			<div>
				<p class="summary__eyebrow">Session Details</p>
				<h1 class="summary__title">${escapeHtml(detail.promptPreview || detail.sessionId)}</h1>
			</div>
			<span class="status">${escapeHtml(detail.status)}</span>
		</div>
		<div class="summary__meta">
			${metaCards.join("")}
		</div>
	</header>
	<section class="conversation">
		<div class="conversation__heading">Conversation</div>
		<div class="conversation__scroll">
			${detail.turns.length > 0
				? detail.turns.map((turn) => renderTurn(turn)).join("")
				: `<div class="empty">${escapeHtml(detail.transcriptAvailable ? "No readable transcript turns were found." : "No transcript is available for this session.")}</div>`}
		</div>
	</section>
</div>`;
}

function renderStatusState(title: string, message: string): string {
	return `<div class="layout">
	<header class="summary">
		<div class="summary__top">
			<div>
				<p class="summary__eyebrow">Session Details</p>
				<h1 class="summary__title">${escapeHtml(title)}</h1>
			</div>
		</div>
	</header>
	<section class="conversation">
		<div class="conversation__heading">Conversation</div>
		<div class="conversation__scroll">
			<div class="empty">${escapeHtml(message)}</div>
		</div>
	</section>
</div>`;
}

function renderMetaCard(label: string, value: string | undefined): string | undefined {
	if (!value) {
		return undefined;
	}

	return `<div class="meta-card">
		<p class="meta-card__label">${escapeHtml(label)}</p>
		<p class="meta-card__value">${escapeHtml(value)}</p>
	</div>`;
}

function renderTurn(turn: EntireSessionDetailModel["turns"][number]): string {
	const timestampLabel = formatShortTimestamp(turn.timestamp);

	return `<article class="turn turn--${escapeHtml(turn.actor.kind)}">
		<div class="turn__meta">
			${renderAvatar(turn.actor)}
			${timestampLabel ? `<time class="timestamp">${escapeHtml(timestampLabel)}</time>` : ""}
		</div>
		<div class="turn__body">
			${turn.text ? `<p class="turn__text">${escapeHtml(turn.text)}</p>` : ""}
			${turn.rawText ? `<pre class="turn__raw">${escapeHtml(turn.rawText)}</pre>` : ""}
			${turn.toolActivities.length > 0 ? `<div class="tools">${turn.toolActivities.map((activity) => renderToolActivity(activity)).join("")}</div>` : ""}
		</div>
	</article>`;
}

function renderAvatar(actor: EntireSessionDetailModel["turns"][number]["actor"]): string {
	if (actor.imageUri) {
		return `<span class="avatar"><img src="${escapeHtml(actor.imageUri)}" alt="" /></span>`;
	}

	return `<span class="avatar">${escapeHtml(actor.initials)}</span>`;
}

function renderToolActivity(activity: EntireSessionDetailModel["turns"][number]["toolActivities"][number]): string {
	const kindLabel = activity.kind === "tool_use" ? "Tool" : "Result";
	const errorClass = activity.isError ? " tool--error" : "";
	return `<div class="tool tool--${escapeHtml(activity.kind)}${errorClass}">
		<div class="tool__label">
			<span class="tool__kind">${escapeHtml(kindLabel)}</span>
			<span>${escapeHtml(activity.label)}</span>
		</div>
		${activity.detail ? `<p class="tool__detail">${escapeHtml(activity.detail)}</p>` : ""}
	</div>`;
}

function formatShortTimestamp(timestamp: string | undefined): string | undefined {
	if (!timestamp) {
		return undefined;
	}

	const date = new Date(timestamp);
	if (Number.isNaN(date.getTime())) {
		return timestamp;
	}

	return new Intl.DateTimeFormat("en", {
		month: "short",
		day: "numeric",
		year: "numeric",
		hour: "numeric",
		minute: "2-digit",
	}).format(date);
}

function formatDuration(durationMs: number | undefined): string | undefined {
	if (durationMs === undefined || !Number.isFinite(durationMs) || durationMs < 0) {
		return undefined;
	}

	const totalSeconds = Math.max(0, Math.floor(durationMs / 1000));
	const days = Math.floor(totalSeconds / 86_400);
	const hours = Math.floor((totalSeconds % 86_400) / 3_600);
	const minutes = Math.floor((totalSeconds % 3_600) / 60);
	const seconds = totalSeconds % 60;

	if (days > 0) {
		return hours > 0 ? `${days}d ${hours}h` : `${days}d`;
	}

	if (hours > 0) {
		return minutes > 0 ? `${hours}h ${minutes}m` : `${hours}h`;
	}

	if (minutes > 0) {
		return seconds > 0 && minutes < 10 ? `${minutes}m ${seconds}s` : `${minutes}m`;
	}

	return `${seconds}s`;
}

function formatTokenCount(count: number): string {
	if (count >= 1_000_000) {
		return `${(count / 1_000_000).toFixed(1)}M`;
	}

	if (count >= 1_000) {
		return `${(count / 1_000).toFixed(1)}k`;
	}

	return String(count);
}

function formatAttribution(detail: EntireSessionDetailModel): string | undefined {
	if (!detail.attribution) {
		return undefined;
	}

	return `${formatPercentage(detail.attribution.agentPercentage)} agent · ${detail.attribution.agentLines}/${detail.attribution.totalCommitted} lines`;
}

function formatPercentage(value: number): string {
	if (!Number.isFinite(value)) {
		return "0%";
	}

	const fixed = value.toFixed(1);
	return `${fixed.endsWith(".0") ? fixed.slice(0, -2) : fixed}%`;
}

function escapeHtml(value: string): string {
	return value
		.replace(/&/g, "&amp;")
		.replace(/</g, "&lt;")
		.replace(/>/g, "&gt;")
		.replace(/"/g, "&quot;")
		.replace(/'/g, "&#39;");
}

