/**
 * Normalizes raw transcript events into human-readable conversation turns suitable
 * for the session details webview. Tool results are attached to the assistant turn
 * that initiated them when linkage metadata is available.
 *
 * @param content Raw transcript content from `full.jsonl` or similar sources.
 * @returns Conversation turns in source order with inline tool activity summaries.
 */
export function buildTranscriptTurns(content: string): NormalizedTranscriptTurn[] {
	const events = parseTranscript(content);
	const turns: MutableTranscriptTurn[] = [];
	const assistantTurnsByUuid = new Map<string, MutableTranscriptTurn>();
	const assistantTurnsByToolUseId = new Map<string, MutableTranscriptTurn>();

	for (const event of events) {
		const record = isJsonObject(event.raw) ? event.raw : undefined;
		const text = extractTurnText(event.raw, event.eventType);
		const toolActivities = dedupeToolActivities(extractToolActivities(event.raw));
		const attachedActivityIds = attachToolResultActivities(
			record,
			toolActivities,
			assistantTurnsByUuid,
			assistantTurnsByToolUseId,
		);
		const remainingToolActivities = toolActivities.filter((activity) => !attachedActivityIds.has(activity.id));
		if (!text && remainingToolActivities.length === 0 && attachedActivityIds.size > 0) {
			continue;
		}

		const actor = classifyTurnActor(record, event.eventType, text, remainingToolActivities);
		const isFallback = !text && remainingToolActivities.length === 0;
		const turn: MutableTranscriptTurn = {
			id: buildTurnId(record, event.index),
			actor,
			timestamp: event.timestamp,
			text,
			toolActivities: remainingToolActivities,
			rawText: isFallback ? event.rawText : undefined,
			isFallback,
			uuid: record ? readString(record, "uuid") : undefined,
		};

		turns.push(turn);
		if (turn.actor === "agent") {
			if (turn.uuid) {
				assistantTurnsByUuid.set(turn.uuid, turn);
			}
			for (const activity of turn.toolActivities) {
				if (activity.kind === "tool_use" && activity.toolUseId) {
					assistantTurnsByToolUseId.set(activity.toolUseId, turn);
				}
			}
		}
	}

	return turns.map((turn) => ({
		id: turn.id,
		actor: turn.actor,
		timestamp: turn.timestamp,
		text: turn.text,
		toolActivities: turn.toolActivities,
		rawText: turn.rawText,
		isFallback: turn.isFallback,
	}));
}

/**
 * Extracts the earliest top-level event timestamp from transcript JSONL content without
 * parsing the entire transcript into normalized events.
 *
 * @param content Raw transcript content, or `null` when unavailable.
 * @returns The earliest timestamp string found near the start of the transcript.
 */
export function extractTranscriptFirstTimestamp(content: string | null): string | undefined {
	if (!content) {
		return undefined;
	}

	for (const line of iterateTranscriptLinesFromStart(content)) {
		const parsed = parseJsonMaybe(line);
		if (!isJsonObject(parsed)) {
			continue;
		}

		const timestamp = readFirstString(parsed, ["timestamp", "ts", "created_at"]);
		if (timestamp) {
			return timestamp;
		}
	}

	return undefined;
}

/**
 * Extracts the latest top-level event timestamp from transcript JSONL content without
 * parsing the entire transcript into normalized events.
 *
 * @param content Raw transcript content, or `null` when unavailable.
 * @returns The latest timestamp string found near the end of the transcript.
 */
export function extractTranscriptLatestTimestamp(content: string | null): string | undefined {
	if (!content) {
		return undefined;
	}

	for (const line of iterateTranscriptLinesFromEnd(content)) {
		const parsed = parseJsonMaybe(line);
		if (!isJsonObject(parsed)) {
			continue;
		}

		const timestamp = readFirstString(parsed, ["timestamp", "ts", "created_at"]);
		if (timestamp) {
			return timestamp;
		}
	}

	return undefined;
}

function parseJsonMaybe(text: string): unknown {
	try {
		return JSON.parse(text) as unknown;
	} catch {
		return undefined;
	}
}

interface MutableTranscriptTurn extends NormalizedTranscriptTurn {
	uuid?: string;
}

function* iterateTranscriptLinesFromStart(content: string): Generator<string> {
	let lineStart = 0;

	for (let index = 0; index < content.length; index += 1) {
		const char = content[index];
		if (char !== "\n" && char !== "\r") {
			continue;
		}

		const line = content.slice(lineStart, index).trim();
		if (line.length > 0) {
			yield line;
		}

		if (char === "\r" && content[index + 1] === "\n") {
			index += 1;
		}
		lineStart = index + 1;
	}

	const lastLine = content.slice(lineStart).trim();
	if (lastLine.length > 0) {
		yield lastLine;
	}
}

function* iterateTranscriptLinesFromEnd(content: string): Generator<string> {
	let lineEnd = content.length;

	for (let index = content.length - 1; index >= 0; index -= 1) {
		const char = content[index];
		if (char !== "\n" && char !== "\r") {
			continue;
		}

		const line = content.slice(index + 1, lineEnd).trim();
		if (line.length > 0) {
			yield line;
		}
		lineEnd = index;
	}

	const firstLine = content.slice(0, lineEnd).trim();
	if (firstLine.length > 0) {
		yield firstLine;
	}
}

function sortTranscriptChunkNames(entryNames: string[]): string[] {
	return [...entryNames].sort((left, right) => {
		const leftIndex = getTranscriptChunkIndex(left) ?? Number.MAX_SAFE_INTEGER;
		const rightIndex = getTranscriptChunkIndex(right) ?? Number.MAX_SAFE_INTEGER;
		if (leftIndex !== rightIndex) {
			return leftIndex - rightIndex;
		}

		return left.localeCompare(right);
	});
}

function getTranscriptChunkIndex(entryName: string): number | undefined {
	const match = entryName.match(/^full\.jsonl\.(\d+)$/);
	if (!match) {
		return undefined;
	}

	const parsed = Number(match[1]);
	return Number.isInteger(parsed) && parsed > 0 ? parsed : undefined;
}

function toTranscriptEvent(index: number, value: unknown, rawText: string): TranscriptEvent {
	if (isJsonObject(value)) {
		return {
			index,
			eventType: readFirstString(value, ["type", "event_type", "eventType", "kind"]),
			timestamp: readFirstString(value, ["timestamp", "ts", "created_at"]),
